import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.lifecycleScope
import kotlinx.coroutines.launch

class MainActivity : AppCompatActivity() {
    private val userRepository = UserRepository()
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        NetworkModule.setEnvironment(Environment.DEV)
        NetworkModule.setAuthToken("your_auth_token_here")
        
        fetchUsers()
    }
    
    private fun fetchUsers() {
        lifecycleScope.launch {
            when (val result = userRepository.getUsers()) {
                is Result.Success -> {
                    val users = result.data
                    println("Fetched ${users.size} users")
                }
                is Result.Error -> {
                    println("Error: ${result.message}")
                }
                is Result.Loading -> {
                    println("Loading...")
                }
            }
        }
    }
    
    private fun fetchUserById(userId: Int) {
        lifecycleScope.launch {
            when (val result = userRepository.getUserById(userId)) {
                is Result.Success -> {
                    val user = result.data
                    println("Fetched user: ${user.name}")
                }
                is Result.Error -> {
                    println("Error: ${result.message}")
                }
                is Result.Loading -> {
                    println("Loading...")
                }
            }
        }
    }
